59			InLevel		: out	std_logic_vector(log2ceil(Depth_g) downto 0);
60	
61			-- Output Status
62			OutFull		: out	std_logic; -- $$ PROC=Input,Output $$
63			OutEmpty	: out	std_logic;
64			OutAlmFull	: out	std_logic;
65			OutAlmEmpty : out 	std_logic;
66			OutLevel	: out	std_logic_vector(log2ceil(Depth_g) downto 0)
67		);
68	end entity;
