73	architecture rtl of psi_common_async_fifo is
74	
75	
76		type two_process_in_r is record
77			WrAddr			: unsigned(log2ceil(Depth_g) downto 0);				-- One additional bit for full/empty detection
78			WrAddrGray		: std_logic_vector(log2ceil(Depth_g) downto 0);
79			RdAddrGraySync	: std_logic_vector(log2ceil(Depth_g) downto 0);
80			RdAddrGray		: std_logic_vector(log2ceil(Depth_g) downto 0);
81			RdAddr			: unsigned(log2ceil(Depth_g) downto 0);
82		end record;
83	
84		type two_process_out_r is record
85			RdAddr			: unsigned(log2ceil(Depth_g) downto 0);				-- One additional bit for full/empty detection
86			RdAddrGray		: std_logic_vector(log2ceil(Depth_g) downto 0);
87			WrAddrGraySync	: std_logic_vector(log2ceil(Depth_g) downto 0);
88			WrAddrGray		: std_logic_vector(log2ceil(Depth_g) downto 0);
89			WrAddr			: unsigned(log2ceil(Depth_g) downto 0);
90		end record;
91	
92		signal ri, ri_next	: two_process_in_r;
93		signal ro, ro_next	: two_process_out_r;
94	
95		signal RstInInt				: std_logic;
96		signal RstOutInt			: std_logic;
97		signal RamWr				: std_logic;
98		signal RamRdAddr			: std_logic_vector(log2ceil(Depth_g)-1 downto 0);
99	
100		attribute syn_srlstyle : string;
101	    attribute syn_srlstyle of ri : signal is "registers";
102	    attribute syn_srlstyle of ro : signal is "registers";
103	
104		attribute shreg_extract : string;
105	    attribute shreg_extract of ri : signal is "no";
106	    attribute shreg_extract of ro : signal is "no";
107	
108		attribute ASYNC_REG : string;
109	    attribute ASYNC_REG of ri : signal is "TRUE";
110	    attribute ASYNC_REG of ro : signal is "TRUE";
111	
112	
113	begin
114		--------------------------------------------------------------------------
115		-- Assertions
116		--------------------------------------------------------------------------
117		assert log2(Depth_g) = log2ceil(Depth_g) report "###ERROR###: psi_common_async_fifo: only power of two Depth_g is allowed" severity error;
118	
119		--------------------------------------------------------------------------
120		-- Combinatorial Process
121		--------------------------------------------------------------------------
122		p_comb : process(InVld, OutRdy, ri, ro)
123			variable vi				: two_process_in_r;
124			variable vo				: two_process_out_r;
125			variable InLevel_v		: unsigned(log2ceil(Depth_g) downto 0);
126			variable OutLevel_v		: unsigned(log2ceil(Depth_g) downto 0);
127		begin
128			-- *** hold variables stable ***
129			vi := ri;
130			vo := ro;
131	
132			-- *** Write Side ***
133			-- Defaults
134			InRdy		<= '0';
135			InFull		<= '0';
136			InEmpty		<= '0';
137			InAlmFull	<= '0';
138			InAlmEmpty	<= '0';
139			RamWr		<= '0';
140	
141			-- Level Detection
142			InLevel_v	:= ri.WrAddr - ri.RdAddr;
143			InLevel		<= std_logic_vector(InLevel_v);
144	
145			-- Full
146			if InLevel_v = Depth_g then
147				InFull	<= '1';
148			else
149				InRdy 	<= '1';
150				-- Execute Write
151				if InVld = '1' then
152					vi.WrAddr	:= ri.WrAddr + 1;
153					RamWr 		<= '1';
154				end if;
155			end if;
156	
157			-- Status Detection
158			if InLevel_v = 0 then
159				InEmpty <= '1';
160			end if;
161			if InLevel_v >= AlmFullLevel_g and AlmFullOn_g then
162				InAlmFull <= '1';
163			end if;
164			if InLevel_v <= AlmEmptyLevel_g and AlmEmptyOn_g then
165				InAlmEmpty <= '1';
166			end if;
167	
168			-- *** Read Side ***
169			-- Defaults
170			OutVld		<= '0';
171			OutFull		<= '0';
172			OutEmpty	<= '0';
173			OutAlmFull	<= '0';
174			OutAlmEmpty	<= '0';
175	
176			-- Level Detection
177			OutLevel_v	:= ro.WrAddr - ro.RdAddr;
178			OutLevel	<= std_logic_vector(OutLevel_v);
179	
180			-- Empty
181			if OutLevel_v = 0 then
182				OutEmpty	<= '1';
183			else
184				OutVld 		<= '1';
185				-- Execute read
186				if OutRdy = '1' then
187					vo.RdAddr	:= ro.RdAddr + 1;
188				end if;
189			end if;
190			RamRdAddr <= std_logic_vector(vo.RdAddr(log2ceil(Depth_g)-1 downto 0));
191	
192			-- Status Detection
193			if OutLevel_v = Depth_g then
194				OutFull	<= '1';
195			end if;
196			if OutLevel_v >= AlmFullLevel_g and AlmFullOn_g then
197				OutAlmFull <= '1';
198			end if;
199			if OutLevel_v <= AlmEmptyLevel_g and AlmEmptyOn_g then
200				OutAlmEmpty <= '1';
201			end if;
202	
203			-- *** Address Clock domain crossings ***
204			-- Bin->Gray is simple, can be done without additional FF
205			vi.WrAddrGray	:= BinaryToGray(std_logic_vector(vi.WrAddr));
206			vo.RdAddrGray	:= BinaryToGray(std_logic_vector(vo.RdAddr));
207	
208			-- Two stage synchronizer
209			vi.RdAddrGraySync	:= ro.RdAddrGray;
210			vi.RdAddrGray		:= ri.RdAddrGraySync;
211			vo.WrAddrGraySync	:= ri.WrAddrGray;
212			vo.WrAddrGray		:= ro.WrAddrGraySync;
213	
214			-- Gray->Bin involves some logic, needs additional FF
215			vi.RdAddr		:= unsigned(GrayToBinary(ri.RdAddrGray));
216			vo.WrAddr		:= unsigned(GrayToBinary(ro.WrAddrGray));
217	
218			-- *** Assign signal ***
219			ri_next <= vi;
220			ro_next <= vo;
221	
222		end process;
223	
224		--------------------------------------------------------------------------
225		-- Sequential
226		--------------------------------------------------------------------------
227		p_seq_in : process(InClk)
228		begin
229			if rising_edge(InClk) then
230				ri <= ri_next;
231				if RstInInt = '1' then
232					ri.WrAddr			<= (others => '0');
233					ri.WrAddrGray		<= (others => '0');
234					ri.RdAddrGraySync	<= (others => '0');
235					ri.RdAddrGray		<= (others => '0');
236				end if;
237			end if;
238		end process;
239	
240		p_seq_out : process(OutClk)
241		begin
242			if rising_edge(OutClk) then
243				ro <= ro_next;
244				if RstOutInt = '1' then
245					ro.RdAddr			<= (others => '0');
246					ro.RdAddrGray		<= (others => '0');
247					ro.WrAddrGraySync	<= (others => '0');
248					ro.WrAddrGray		<= (others => '0');
249				end if;
250			end if;
251		end process;
252	
253		--------------------------------------------------------------------------
254		-- Component Instantiations
255		--------------------------------------------------------------------------
256		i_ram : entity work.psi_common_tdp_ram_rbw
257			generic map (
258				Depth_g		=> Depth_g,
259				Width_g		=> Width_g
260			)
261			port map (
262				-- Port A
263				ClkA		=> InClk,
264				AddrA		=> std_logic_vector(ri.WrAddr(log2ceil(Depth_g)-1 downto 0)),
265				WrA			=> RamWr,
266				DinA		=> InData,
267				DoutA		=> open,
268	
269				-- Port B
270				ClkB		=> OutClk,
271				AddrB		=> RamRdAddr,
272				WrB			=> '0',
273				DinB		=> (others => '0'),
274				DoutB		=> OutData
275			);
276	
277		-- only used for reset crossing and oring
278		i_rst_cc : entity work.psi_common_pulse_cc
279			port map (
280				-- Clock Domain A
281				ClkA		=> InClk,
282				RstInA		=> InRst,
283				RstOutA		=> RstInInt,
284				PulseA		=> (others => '0'),
285	
286				-- Clock Domain B
287				ClkB		=> OutClk,
288				RstInB		=> OutRst,
289				RstOutB		=> RstOutInt,
290				PulseB		=> open
291			);
292	
293	
294	end;
